const config = $input.first()?.json || {};

function cleanConfig(value) {
  const text = String(value || '').trim();
  if (!text || text.startsWith('PEGAR_')) return '';
  return text;
}

const exaApiKey = cleanConfig(config.exa_api_key);
const trabajoyaApiKey = cleanConfig(config.trabajoya_api_key);
const trabajoyaBaseUrl = (cleanConfig(config.trabajoya_base_url) || 'https://trabajoya.rivasystems.dev').replace(/\/$/, '');

if (!exaApiKey) {
  throw new Error('Edita el nodo "Configurar llaves" y pega exa_api_key.');
}

if (!trabajoyaApiKey) {
  throw new Error('Edita el nodo "Configurar llaves" y pega trabajoya_api_key.');
}

const sources = [
  {
    source: 'incaf',
    provider: 'INCAF',
    query: 'cursos formacion disponible El Salvador INCAF',
    includeDomains: ['incaf.gob.sv', 'www.incaf.gob.sv'],
    area: 'Formacion tecnica',
    modality: 'mixta',
    isFree: true,
  },
  {
    source: 'platzi_gob_sv',
    provider: 'Platzi / Gobierno de El Salvador',
    query: 'Platzi gratis Gobierno de El Salvador cursos formacion jovenes empleo certificate.gob.sv',
    includeDomains: ['certificate.gob.sv', 'platzi.com'],
    area: 'Tecnologia y habilidades digitales',
    modality: 'online',
    isFree: true,
  },
];

return sources.map((source, index) => ({
  json: {
    source_index: index,
    exa_api_key: exaApiKey,
    trabajoya_api_key: trabajoyaApiKey,
    trabajoya_base_url: trabajoyaBaseUrl,
    source_config: source,
    request_body: {
      query: source.query,
      includeDomains: source.includeDomains,
      numResults: 10,
      contents: {
        highlights: true,
        text: {
          maxCharacters: 1800,
        },
      },
    },
  },
}));

const preparedItems = $items('Preparar busquedas');
const exaItems = $input.all();

const skillKeywords = [
  ['programacion', ['Programacion', 'Logica', 'Tecnologia']],
  ['software', ['Software', 'Tecnologia']],
  ['excel', ['Excel', 'Ofimatica']],
  ['office', ['Ofimatica']],
  ['ingles', ['Ingles']],
  ['ventas', ['Ventas', 'Atencion al cliente']],
  ['cliente', ['Atencion al cliente', 'Comunicacion']],
  ['marketing', ['Marketing digital']],
  ['datos', ['Analisis de datos']],
  ['inteligencia artificial', ['Inteligencia artificial']],
  ['gastronomia', ['Gastronomia']],
  ['turismo', ['Turismo']],
  ['emprendedor', ['Emprendimiento']],
  ['emprendimiento', ['Emprendimiento']],
];

function cleanText(value) {
  return String(value || '').replace(/\s+/g, ' ').trim();
}

function unique(values) {
  return [...new Set(values.filter(Boolean))];
}

function inferSkills(text) {
  const lower = cleanText(text).toLowerCase();
  const skills = [];

  for (const [keyword, mappedSkills] of skillKeywords) {
    if (lower.includes(keyword)) {
      skills.push(...mappedSkills);
    }
  }

  return unique(skills).slice(0, 12);
}

function inferTargetRoles(skills) {
  const roles = [];

  if (skills.includes('Atencion al cliente')) roles.push('Asesor de servicio', 'Auxiliar de tienda');
  if (skills.includes('Ventas')) roles.push('Vendedor', 'Ejecutivo comercial');
  if (skills.includes('Programacion')) roles.push('Desarrollador junior');
  if (skills.includes('Ofimatica')) roles.push('Auxiliar administrativo');
  if (skills.includes('Gastronomia')) roles.push('Auxiliar de cocina');
  if (skills.includes('Turismo')) roles.push('Atencion turistica');

  return unique(roles).slice(0, 8);
}

function normalizeResult(source, result) {
  const title = cleanText(result.title || result.url);
  const highlightText = Array.isArray(result.highlights) ? result.highlights.join(' ') : '';
  const description = cleanText(highlightText || result.text || title).slice(0, 2500);
  const skills = inferSkills(title + ' ' + description);

  return {
    source: source.source,
    provider: source.provider,
    title,
    area: source.area,
    description,
    modality: source.modality,
    country: 'El Salvador',
    is_free: source.isFree,
    cost: source.isFree ? 0 : null,
    currency: 'USD',
    skills,
    target_roles: inferTargetRoles(skills),
    source_url: result.url,
    status: 'active',
    raw: {
      exa_id: result.id,
      published_date: result.publishedDate,
      query: source.query,
      score: result.score,
      highlights: result.highlights || [],
    },
  };
}

const outputs = [];

for (let index = 0; index < exaItems.length; index += 1) {
  const prepared = preparedItems[index]?.json;
  const source = prepared?.source_config;

  if (!source) {
    throw new Error('No se encontro configuracion de fuente para el item ' + index + '.');
  }

  const exaData = exaItems[index].json || {};
  const results = Array.isArray(exaData.results) ? exaData.results : [];
  const courses = results
    .filter((result) => result?.url && result?.title)
    .map((result) => normalizeResult(source, result));

  if (courses.length === 0) {
    continue;
  }

  outputs.push({
    json: {
      source: source.source,
      result_count: results.length,
      course_count: courses.length,
      trabajoya_base_url: prepared.trabajoya_base_url,
      trabajoya_api_key: prepared.trabajoya_api_key,
      payload: {
        source: source.source,
        sync: {
          provider: source.provider,
          query: source.query,
          include_domains: source.includeDomains,
          ran_at: new Date().toISOString(),
        },
        courses,
      },
    },
  });
}

return outputs;
